## Frame Time Profiling

Instrument the rendering engine to track frame times:

```csharp
public class SkiaRenderingEngine
{
    private readonly Queue<long> _frameTimings = new(capacity: 120);
    private readonly Stopwatch _frameTimer = new();

    public void RenderFrame(SKCanvas canvas)
    {
        _frameTimer.Restart();

        try
        {
            // Perform rendering
            RenderAllViews(canvas);
        }
        finally
        {
            _frameTimer.Stop();
            RecordFrameTime(_frameTimer.ElapsedMilliseconds);
        }
    }

    private void RecordFrameTime(long milliseconds)
    {
        if (_frameTimings.Count >= 120)
        {
            _frameTimings.Dequeue();
        }

        _frameTimings.Enqueue(milliseconds);

        // Log slow frames
        if (milliseconds > 16)
        {
            Debug.WriteLine($"⚠️ Slow frame: {milliseconds}ms (target: 16ms)");
        }
    }

    public FrameStatistics GetStatistics()
    {
        var timings = _frameTimings.ToArray();

        return new FrameStatistics
        {
            AverageFrameTime = timings.Average(),
            MinFrameTime = timings.Min(),
            MaxFrameTime = timings.Max(),
            P95FrameTime = Percentile(timings, 0.95),
            P99FrameTime = Percentile(timings, 0.99),
            DroppedFrames = timings.Count(t => t > 16)
        };
    }

    private static double Percentile(long[] sortedValues, double percentile)
    {
        Array.Sort(sortedValues);
        int index = (int)Math.Ceiling(percentile * sortedValues.Length) - 1;
        return sortedValues[Math.Max(0, Math.Min(index, sortedValues.Length - 1))];
    }
}
```

