### Rendering Budget (Target: <8ms)

```csharp
public class RenderBudget
{
    // Per-view render budgets
    public const double SimpleShape = 0.1;      // BoxView, Border
    public const double Text = 0.5;             // Label (with shaping)
    public const double Image = 0.3;            // Image (cached)
    public const double ComplexControl = 1.0;   // Button with text+icon

    // Total frame render
    public const double FrameRender = 8.0;      // All views

    public static void MeasureRender(SkiaView view, SKCanvas canvas, Action<SKCanvas> drawAction)
    {
        var sw = Stopwatch.StartNew();
        drawAction(canvas);
        sw.Stop();

        var budget = view switch
        {
            SkiaLabel => Text,
            SkiaImage => Image,
            SkiaButton or SkiaImageButton => ComplexControl,
            _ => SimpleShape
        };

        if (sw.Elapsed.TotalMilliseconds > budget)
        {
